#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        long long ans = 0, len = 0;
        for(int i=0;i<N;i++){
            int x; scanf("%d", &x);
            if(x==1) len++;
            else{ ans += len*(len+1)/2; len = 0; }
        }
        ans += len*(len+1)/2; // last segment
        printf("%lld\n", ans);
    }
    return 0;
}

